#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding asthma-assessment (14 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    age:int \
    sex:string! \
    ethnicity:string! \
    occupation:string! \
    postcode:string! \
    age_at_diagnosis:int \
    referring_clinician:string! \
    --htmx

cargo loco generate scaffold assessment_symptom_frequency \
    assessment:references \
    act_q1_activity_limitation:int \
    act_q2_shortness_of_breath:int \
    act_q3_night_symptoms:int \
    act_q4_rescue_inhaler_use:int \
    act_q5_self_rated_control:int \
    daytime_symptom_frequency:string! \
    nocturnal_symptom_frequency:string! \
    exercise_induced_symptoms:string! \
    --htmx

cargo loco generate scaffold assessment_lung_function \
    assessment:references \
    fev1_litres:double \
    fev1_percent_predicted:double \
    fvc_litres:double \
    fev1_fvc_ratio:double \
    pef_litres_per_min:double \
    pef_percent_predicted:double \
    pef_variability_percent:double \
    reversibility_test_done:string! \
    reversibility_percent:double \
    spirometry_date:date \
    spirometry_notes:text! \
    --htmx

cargo loco generate scaffold assessment_triggers \
    assessment:references \
    trigger_dust_mites:string! \
    trigger_pollen:string! \
    trigger_animal_dander:string! \
    trigger_mould:string! \
    trigger_cold_air:string! \
    trigger_exercise:string! \
    trigger_infections:string! \
    trigger_tobacco_smoke:string! \
    trigger_occupational:string! \
    occupational_trigger_details:text! \
    trigger_stress:string! \
    trigger_nsaids:string! \
    other_triggers:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    uses_saba_reliever:string! \
    saba_name:string! \
    saba_frequency:string! \
    uses_ics_preventer:string! \
    ics_name:string! \
    ics_dose:string! \
    uses_laba:string! \
    laba_name:string! \
    uses_ltra:string! \
    ltra_name:string! \
    uses_biologic:string! \
    biologic_name:string! \
    uses_oral_corticosteroid:string! \
    oral_corticosteroid_details:text! \
    inhaler_technique_checked:string! \
    adherence_self_rating:string! \
    other_medications:text! \
    --htmx

cargo loco generate scaffold assessment_allergies \
    assessment:references \
    has_atopic_history:string! \
    has_eczema:string! \
    has_allergic_rhinitis:string! \
    has_food_allergies:string! \
    food_allergy_details:text! \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    has_anaphylaxis_history:string! \
    anaphylaxis_details:text! \
    allergy_testing_done:string! \
    allergy_testing_results:text! \
    total_ige_level:double \
    --htmx

cargo loco generate scaffold assessment_exacerbation_history \
    assessment:references \
    exacerbations_past_12_months:int \
    oral_steroid_courses_past_12_months:int \
    ed_visits_past_12_months:int \
    hospital_admissions_past_12_months:int \
    icu_admissions_ever:int \
    intubation_history:string! \
    worst_exacerbation_details:text! \
    has_asthma_action_plan:string! \
    --htmx

cargo loco generate scaffold assessment_comorbidities \
    assessment:references \
    has_gord:string! \
    has_obesity:string! \
    has_obstructive_sleep_apnoea:string! \
    has_nasal_polyps:string! \
    has_anxiety:string! \
    has_depression:string! \
    has_vocal_cord_dysfunction:string! \
    has_copd_overlap:string! \
    has_bronchiectasis:string! \
    other_comorbidities:text! \
    --htmx

cargo loco generate scaffold assessment_social_history \
    assessment:references \
    smoking_status:string! \
    pack_years:double \
    vaping_status:string! \
    passive_smoke_exposure:string! \
    housing_type:string! \
    housing_damp_or_mould:string! \
    pets_in_home:string! \
    pet_details:text! \
    occupational_exposures:text! \
    exercise_frequency:string! \
    impact_on_daily_life:text! \
    days_missed_work_or_school:int \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    act_total_score:int \
    control_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    control_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
